  ('retired-10ced7e2-moex-00213', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '稀缺性高科技人才的人事制度設計之核心原則，下列何者較不適用？ 企業家精神  市場競爭  層級節制  創意績效', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00214', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '有關我國現行公務人員俸給制度的內涵，下列敘述何者正確？ 本俸是底薪，年功俸是績效薪 服務處所越偏遠，職務加給越高 經銓敘審定之俸級應予保障，非依法律不得降級或減俸 各機關得依機關特性，另行自定俸給項目及數額支給', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00215', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '有關「國民租稅負擔率」的敘述，下列何者正確？ 可作為衡量社會福利支出是否有效率的指標 即政府賦稅收入占國內生產毛額的比率 我國近5年的國民租稅負擔率介於45~55%之間 提高租稅負擔率的方式之一為降低公共支出', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00216', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '若我國中央政府總預算案未及於會計年度開始前完成三讀，對政府單位預算的運作有何影響？ 政府單位除必要工作者（essential workers）可繼續上班之外，其他人員應暫停上班，直到預算 案完成三讀為止 由總統頒布臨時預算，作為各機關預算執行之依據 如總預算案未能如期完成三讀，依法視同自動完成三讀，故對政府運作其實並無任何影響 新興資本支出及新增計畫須待預算審議完成後始得動支', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00217', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '政府採購法分為公開招標、選擇性招標及限制性招標三種招標程序，關於此三種招標程序之規定， 下列敘述何者正確？ 三種招標方式都需經公告程序  公開招標與選擇性招標需經公告程序 公開招標與限制性招標需經公告程序  僅公開招標需經公告程序 13550、13750', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00218', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '有人說績效評估容易造成目標錯置，這句話的意思為何？ 組織中高階人員與低階人員對目標的定義不同 執行任務後發現與既定的策略目標有落差 誤把績效指標當成目的性的組織價值與信仰 組織缺乏學習能力，無法將績效評估結果回饋到新的做法上', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00219', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '下列那一項不屬於布雷克（R. R. Blake）與毛頓（J. S. Mouton）依其「管理格道」所發展之五種 領導類型？ 權威服從式管理  走動式管理  無為式管理  團隊式管理', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00220', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '進行災害管理與應變時，下列何者錯誤？ 需釐清災害種類及性質 分為減災、整備、應變、復原，其中最重要的階段是減災 災害管理各階段均應獨立規劃，以達最大綜效 災害應變的原則，其順序為自助、互助、公助', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00221', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '關於我國推動「智慧國家方案」之敘述，下列何者錯誤？ 以促進國家社會整體數位轉型，建構智慧國家新典範 以促進社會整備（Society Ready）為核心 以「數位基盤」、「數位創新」、「數位治理」及「數位包容」為主軸 以「2050實現創新、包容、淨零碳排之智慧國家」為願景', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00222', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '依據史奈德（A. Schneider）和英格恩（H. Ingram）之論點，以新冠肺炎防疫為例，中央流行疫 情指揮中心每日召開直播記者會，公布疫情資訊及說明防疫指引。此較接近下列何種政策工具 類型？ 權威（authoritarian）型  能力建立（capacity-building）型 誘因（incentive）型    管制（regulation）型', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL)
